      /* <flatten type="Javascript"> */
function active$VoucherFilter$(f) {
  f.add_onResponseComplete(on$Filter$ResponseComplete);
  var l = (f.getItemValue('den_nam') == 0);
  if (l) {
    f.getItem('tu_ky').value = (new Date()).getMonth() + 1;
    f.getItem('den_ky').value = (new Date()).getMonth() + 1;
    f.getItem('tu_nam').value = (new Date()).getFullYear();
    f.getItem('den_nam').value = (new Date()).getFullYear();
  }
  f.live(f.getItem('tu_ky'));
  if (!l) onChange$Filter$ReportForm(f.getItem('ma_dvcs'));
}
function close$VoucherFilter$(f) {try {f.remove_onResponseComplete(on$Filter$ResponseComplete);} catch (ex) {}}
function on$Filter$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      var g = f.grid;
      g._hiddenFields = [{Fields: 'dd_dk_nt, ps_tk_nt, dd_ck_nt, tong_gt_nt, gia_nt', Value: (f.getItemValue('mau_bc')) == '10'},
        {Fields: 'dd_dk, ps_tk, dd_ck, tong_gt, gia', Value: (f.getItemValue('mau_bc')) == '20'}
      ];
      var d1 = f.getItemValue('tu_ky'), d2 = f.getItemValue('tu_nam'), d3 = f.getItemValue('den_ky'), d4 = f.getItemValue('den_nam');
      var s1 = f.getItemValue('ma_sp'), sp = '', bp = '', lsx = '';
      if (f._language == 'v') {sp = 'sản phẩm: '; bp = ', bộ phận: '; lsx = ', lệnh sản xuất: ';}
        else {sp = 'Product: '; bp = ', Department: '; lsx = ', MO: '; }
      f.getItemValue('ten_sp%l') == '' ? s1 = sp + s1 : s1 = sp + s1 + ' - ' + f.getItemValue('ten_sp%l');
      if (f.getItemValue('ma_bp') != '') s1 = s1 + bp + f.getItemValue('ma_bp');
      if (f.getItemValue('so_lsx') != '') s1 = s1 + lsx + f.getItemValue('so_lsx');

      g._alterTitle = [null, [['%d1', d1, true], ['%d2', d2, true], ['%d3', d3, true], ['%d4', d4, true], ['%s1', s1, true]]];
      remove$GridReport$Filter(g);
      break;
    case 'SetReadOnlyField':
      setItemReadOnly(f, 'ma_bp', result[0].Value, true);
      setItemReadOnly(f, 'so_lsx', result[1].Value, true);
      break;
    default:
      break;
  }
}
function onChange$Filter$ReportForm(o) {if (o.parentForm._objectUnit == '1') o.parentForm.request('GetResponse', 'SetReadOnlyField', ['ma_dvcs'])}
/* </flatten> */

